### 1. Key Parsing Roundtrip Tests
```rust
#[cfg(test)]
mod key_roundtrip_tests {
    use proptest::prelude::*;
    use bubbletea::key::{Key, KeyEvent};

    proptest! {
        #[test]
        fn key_roundtrip(key in arb_key_event()) {
            // Serialize to bytes
            let bytes = key.to_bytes();

            // Parse back
            let parsed = KeyEvent::from_bytes(&bytes);

            // Should match original
            prop_assert_eq!(parsed.unwrap(), key);
        }

        #[test]
        fn key_display_roundtrip(key in arb_key_event()) {
            // Convert to display string
            let display = format!("{}", key);

            // Parse from display string
            let parsed = KeyEvent::parse(&display);

            // Should match original
            prop_assert_eq!(parsed.unwrap(), key);
        }
    }
}
```

