use criterion::{black_box, Criterion, BenchmarkId, Throughput};

/// Standard benchmark configuration
pub fn configure() -> Criterion {
    Criterion::default()
        .sample_size(100)
        .measurement_time(std::time::Duration::from_secs(5))
        .warm_up_time(std::time::Duration::from_secs(1))
}

/// Create parameterized benchmarks
pub fn bench_with_sizes<F>(c: &mut Criterion, name: &str, sizes: &[usize], f: F)
where
    F: Fn(usize) -> String,
{
    let mut group = c.benchmark_group(name);
    for &size in sizes {
        group.throughput(Throughput::Elements(size as u64));
        group.bench_with_input(
            BenchmarkId::from_parameter(size),
            &size,
            |b, &size| {
                let input = f(size);
                b.iter(|| black_box(process(&input)))
            },
        );
    }
    group.finish();
}
```

### 4. Benchmark Template
