    c.bench_function("Style::new", |b| {
        b.iter(|| {
            black_box(lipgloss::Style::new())
        });
    });
}

fn benchmark_style_rendering(c: &mut Criterion) {
    let style = lipgloss::Style::new()
        .foreground(lipgloss::Color::rgb(255, 0, 0))
        .bold(true);

    c.bench_function("Style::render short", |b| {
        b.iter(|| {
            black_box(style.render("Hello"))
        });
    });

    let long_text = "x".repeat(1000);
    c.bench_function("Style::render long", |b| {
        b.iter(|| {
            black_box(style.render(&long_text))
        });
    });
}

criterion_group!(benches, benchmark_style_creation, benchmark_style_rendering);
criterion_main!(benches);
```

